Output the COMPLETE new content of `x.go`.

```go
package sandbox

import (
	"errors"
	"unicode/utf8"
)

// ErrInvalidUTF8 is returned when a string is not valid UTF-8.
var ErrInvalidUTF8 = errors.New("invalid UTF-8")

// RuneLen returns the number of runes in s.
func RuneLen(s string) int {
	return utf8.RuneCountInString(s)
}

// ValidRuneLen returns the rune count of s, or ErrInvalidUTF8 if s contains
// invalid UTF-8.
func ValidRuneLen(s string) (int, error) {
	if !utf8.ValidString(s) {
		return 0, ErrInvalidUTF8
	}
	return utf8.RuneCountInString(s), nil
}
```

You are maintaining an existing Go project. Apply this change:

CHANGE REQUEST: Title uses byte slicing (`w[:1]`) to capitalize the first letter, which breaks for words starting with a multi-byte UTF-8 rune (e.g. "éric"). Fix it to capitalize the first rune correctly.

Here is the current `x.go`:
```go
package sandbox

import "strings"

// Title capitalizes the first letter of each space-separated word.
func Title(s string) string {
	words := strings.Fields(s)
	for i, w := range words {
		words[i] = strings.ToUpper(w[:1]) + w[1:]
	}
	return strings.Join(words, " ")
}
```
Output the COMPLETE new content of `x.go`.

```go
package sandbox

import (
	"strings"
	"unicode"
	"unicode/utf8"
)

// Title capitalizes the first rune of each space-separated word, handling
// multi-byte UTF-8 characters correctly.
func Title(s string) string {
	words := strings.Fields(s)
	for i, w := range words {
		r, size := utf8.DecodeRuneInString(w)
		if r == utf8.RuneError {
			continue
		}
		words[i] = string(unicode.ToUpper(r)) + w[size:]
	}
	return strings.Join(words, " ")
}
```

