```go
package sandbox

import "strings"

// StripNonASCII removes every rune outside the ASCII range from s. When repl
// is non-negative, each non-ASCII rune is replaced by repl instead of dropped.
func StripNonASCII(s string, repl rune) string {
	var b strings.Builder
	for _, r := range s {
		switch {
		case r < 128:
			b.WriteRune(r)
		case repl >= 0:
			b.WriteRune(repl)
		}
	}
	return b.String()
}
```

