	s.items = append(s.items, v)
}

// Pop removes and returns the top value. The boolean is false if the stack
// is empty.
func (s *Stack[T]) Pop() (T, bool) {
	var zero T
	if len(s.items) == 0 {
		return zero, false
	}
	top := s.items[len(s.items)-1]
	s.items = s.items[:len(s.items)-1]
