package sandbox

import (
	"cmp"
	"errors"
)

// ErrEmpty is returned by Max when called on an empty slice.
var ErrEmpty = errors.New("sandbox: empty slice")

// Max returns the largest element of s. It returns ErrEmpty if s is empty.
func Max[T cmp.Ordered](s []T) (T, error) {
	if len(s) == 0 {
		var zero T
		return zero, ErrEmpty
	}
	best := s[0]
	for _, v := range s[1:] {
		if v > best {
			best = v
		}
	}
