```go
package sandbox

// List is a growable, generic sequence of values.
type List[T any] struct {
	items []T
}

// Option configures a List during construction.
type Option[T any] func(*List[T])

// WithCapacity preallocates backing storage for at least n elements.
func WithCapacity[T any](n int) Option[T] {
	return func(l *List[T]) {
		l.items = make([]T, 0, n)
	}
}

// New returns a new List configured by the given options.
func New[T any](opts ...Option[T]) *List[T] {
	l := &List[T]{}
	for _, opt := range opts {
		opt(l)
	}
	return l
}

// Append adds v to the end of the list.
func (l *List[T]) Append(v T) {
	l.items = append(l.items, v)
}

// Len returns the number of elements in the list.
func (l *List[T]) Len() int {
	return len(l.items)
}
```

