Output the COMPLETE new content of `x.go`.

```go
package sandbox

// Chunk splits s into contiguous sub-slices, each of length size (the final
// chunk may be shorter). It returns nil when size is not positive, avoiding
// an infinite loop.
func Chunk[T any](s []T, size int) [][]T {
	if size <= 0 {
		return nil
	}
	var out [][]T
	for i := 0; i < len(s); i += size {
		end := i + size
		if end > len(s) {
			end = len(s)
		}
		out = append(out, s[i:end])
	}
	return out
}
```

