package sandbox

import "fmt"

// Config holds string settings keyed by name.
type Config struct {
	values map[string]string
}

// NewConfig returns a Config initialized with values.
func NewConfig(values map[string]string) *Config {
	return &Config{values: values}
}

// Get returns the value for key. It returns an error if the key is absent so
// callers can distinguish a missing key from an empty value.
func (c *Config) Get(key string) (string, error) {
