```go
package sandbox

import (
	"errors"
	"fmt"
)

// Sentinel errors returned by Queue operations.
var (
	ErrClosed = errors.New("closed")
	ErrEmpty  = errors.New("empty")
)

// Queue is a simple FIFO queue.
type Queue struct {
	items  []int
	closed bool
}

// Push appends v unless the queue is closed.
func (q *Queue) Push(v int) error {
	if q.closed {
		return ErrClosed
	}
	q.items = append(q.items, v)
	return nil
}

// Pop removes and returns the front item, or a wrapped ErrEmpty if none.
func (q *Queue) Pop() (int, error) {
	if len(q.items) == 0 {
		return 0, fmt.Errorf("pop: %w", ErrEmpty)
	}
	v := q.items[0]
	q.items = q.items[1:]
	return v, nil
}
```

