package sandbox

import (
	"encoding/json"
	"strconv"
	"strings"
)

// User holds a decoded user record.
type User struct {
	ID   int64  `json:"id"`
	Name string `json:"name"`
}

// UnmarshalJSON accepts "id" as either a JSON number or a quoted string.
func (u *User) UnmarshalJSON(data []byte) error {
	var raw struct {
		ID   json.RawMessage `json:"id"`
		Name string          `json:"name"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	u.Name = raw.Name
	if len(raw.ID) == 0 {
		return nil
	}
	id, err := strconv.ParseInt(strings.Trim(string(raw.ID), `"`), 10, 64)
	if err != nil {
		return err
	}
	u.ID = id
	return nil
}

// ParseUser decodes a user from JSON bytes.
func ParseUser(data []byte) (User, error) {
	var u User
	err := json.Unmarshal(data, &u)
	return u, err
}
```

