package sandbox

import "container/heap"

// Item is an element managed by the priority queue.
type Item struct {
	Value    string
	Priority int
}

// PriorityQueue implements heap.Interface as a max-heap by Priority.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].Priority > pq[j].Priority
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x any) {
	*pq = append(*pq, x.(*Item))
}

func (pq *PriorityQueue) Pop() any {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	*pq = old[:n-1]
	return item
}

// NewPriorityQueue returns an initialized, empty priority queue.
func NewPriorityQueue() *PriorityQueue {
	pq := &PriorityQueue{}
	heap.Init(pq)
	return pq
}

// Update changes the priority of item and restores the heap ordering.
func (pq *PriorityQueue) Update(item *Item, priority int) {
	item.Priority = priority
	for i := range *pq {
		if (*pq)[i] == item {
			heap.Fix(pq, i)
			return
		}
	}
}
