import "errors"

// ErrFull is returned by Push when the buffer has no free slot.
var ErrFull = errors.New("ring buffer is full")

// RingBuffer is a fixed-capacity FIFO ring buffer of ints.
type RingBuffer struct {
	data  []int
	head  int
	tail  int
	count int
}

// NewRingBuffer returns a buffer with the given capacity.
func NewRingBuffer(capacity int) *RingBuffer {
	return &RingBuffer{data: make([]int, capacity)}
}

// Push appends v to the buffer, or returns ErrFull when the buffer is
// already at capacity.
func (b *RingBuffer) Push(v int) error {
	if b.count == len(b.data) {
		return ErrFull
	}
	b.data[b.tail] = v
	b.tail = (b.tail + 1) % len(b.data)
	b.count++
	return nil
}

// Pop removes and returns the oldest value and true, or 0 and false
// when the buffer is empty.
func (b *RingBuffer) Pop() (int, bool) {
	if b.count == 0 {
		return 0, false
	}
	v := b.data[b.head]
	b.head = (b.head + 1) % len(b.data)
	b.count--
	return v, true
}
