// Node is an element of the linked list.
type Node struct {
	Val  int
	Next *Node
}

// LinkedList is a singly linked list of ints.
type LinkedList struct {
	head *Node
}

// Append adds v to the end of the list.
func (l *LinkedList) Append(v int) {
	n := &Node{Val: v}
	if l.head == nil {
		l.head = n
		return
	}
	cur := l.head
	for cur.Next != nil {
		cur = cur.Next
	}
	cur.Next = n
}

// Get returns the value at position i and true, or 0 and false when i
// is negative or out of range, instead of panicking.
func (l *LinkedList) Get(i int) (int, bool) {
	if i < 0 {
		return 0, false
	}
	cur := l.head
	for ; i > 0 && cur != nil; i-- {
		cur = cur.Next
	}
	if cur == nil {
		return 0, false
	}
	return cur.Val, true
}
