package sandbox

import "strings"

// Option configures ParseList.
type Option func(*config)

type config struct {
	sep string
}

// WithSeparator sets the field separator (default ",").
func WithSeparator(sep string) Option {
	return func(c *config) { c.sep = sep }
}

// ParseList splits input into trimmed, non-empty items. By default items
// are separated by commas; use WithSeparator to override.
func ParseList(input string, opts ...Option) []string {
	cfg := config{sep: ","}
	for _, opt := range opts {
		opt(&cfg)
	}
	var items []string
	for _, part := range strings.Split(input, cfg.sep) {
		part = strings.TrimSpace(part)
		if part != "" {
			items = append(items, part)
		}
	}
	return items
}
