// Normalize returns a new unit vector pointing in the same direction as v.
// If v has zero norm, it returns a zero-filled copy of the same length.
func Normalize(v []float64) []float64 {
	out := make([]float64, len(v))
	n := Norm(v)
	if n == 0 {
		return out
	}
	for i, x := range v {
		out[i] = x / n
	}
	return out
}
