// Zip combines a and b into an iterator of pairs, stopping as soon as
// either input iterator is exhausted.
func Zip[A, B any](a iter.Seq[A], b iter.Seq[B]) iter.Seq2[A, B] {
	return func(yield func(A, B) bool) {
		nextA, stopA := iter.Pull(a)
		defer stopA()
		nextB, stopB := iter.Pull(b)
		defer stopB()
		for {
			av, okA := nextA()
			bv, okB := nextB()
			if !okA || !okB {
				return
			}
			if !yield(av, bv) {
				return
			}
		}
	}
}
