package sandbox

import (
	"sync"
	"time"
)

// FixedWindow allows up to limit events per window.
type FixedWindow struct {
	mu      sync.Mutex
	limit   int
	window  time.Duration
	count   int
	resetAt time.Time
}

// NewFixedWindow creates a fixed-window limiter.
func NewFixedWindow(limit int, window time.Duration) *FixedWindow {
	return &FixedWindow{
		limit:   limit,
		window:  window,
		resetAt: time.Now().Add(window),
	}
}

// Allow reports whether an event may proceed in the current window.
func (w *FixedWindow) Allow() bool {
	w.mu.Lock()
	defer w.mu.Unlock()
	now := time.Now()
	if now.After(w.resetAt) {
		w.count = 0
		w.resetAt = now.Add(w.window)
	}
	if w.count < w.limit {
		w.count++
		return true
	}
	return false
}

// Remaining returns how many events are still allowed in the current window,
// rolling the window over first if it has already elapsed.
func (w *FixedWindow) Remaining() int {
	w.mu.Lock()
	defer w.mu.Unlock()
	now := time.Now()
	if now.After(w.resetAt) {
		w.count = 0
		w.resetAt = now.Add(w.window)
	}
	if r := w.limit - w.count; r > 0 {
		return r
	}
	return 0
}
