package sandbox

import (
	"context"
	"errors"
	"time"
)

// Retry calls fn up to attempts times, sleeping delay between tries,
// and returns the last error if every attempt fails. It aborts early,
// returning the context error, if ctx is cancelled while waiting.
func Retry(ctx context.Context, attempts int, delay time.Duration, fn func() error) error {
	var err error
	for i := 0; i < attempts; i++ {
		err = fn()
		if err == nil {
			return nil
		}
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-time.After(delay):
		}
	}
	if err == nil {
		err = errors.New("retry: no attempts made")
	}
	return err
}
