// LeakyBucket throttles by leaking at most one event per interval.
type LeakyBucket struct {
	interval time.Duration
	last     time.Time
}

// NewLeakyBucket creates a leaky bucket that permits one event per interval.
// It returns an error if interval is not strictly positive.
func NewLeakyBucket(interval time.Duration) (*LeakyBucket, error) {
	if interval <= 0 {
		return nil, errors.New("leaky bucket: interval must be positive")
	}
	return &LeakyBucket{interval: interval}, nil
}

// Allow reports whether an event may pass at time now.
func (b *LeakyBucket) Allow(now time.Time) bool {
	if now.Sub(b.last) >= b.interval {
		b.last = now
		return true
	}
	return false
}
