// AIMD adjusts a concurrency limit using
// additive-increase / multiplicative-decrease.
type AIMD struct {
	mu    sync.Mutex
	limit int
}

// NewAIMD creates an AIMD controller starting at the given limit.
func NewAIMD(start int) *AIMD {
	return &AIMD{limit: start}
}

// OnSuccess additively increases the limit by one.
func (a *AIMD) OnSuccess() {
	a.mu.Lock()
	a.limit++
	a.mu.Unlock()
}

// OnFailure multiplicatively decreases the limit by half,
// but never below a floor of 1.
func (a *AIMD) OnFailure() {
	a.mu.Lock()
	a.limit /= 2
	if a.limit < 1 {
		a.limit = 1
	}
	a.mu.Unlock()
}

// Limit returns the current limit.
func (a *AIMD) Limit() int {
	a.mu.Lock()
	defer a.mu.Unlock()
	return a.limit
}
