package sandbox

import (
	"sync"
	"time"
)

// Registry maps each key to its own fixed-interval limiter.
type Registry struct {
	mu       sync.Mutex
	interval time.Duration
	last     map[string]time.Time
}

// NewRegistry creates a registry that limits each key to one event per interval.
func NewRegistry(interval time.Duration) *Registry {
	return &Registry{
		interval: interval,
		last:     make(map[string]time.Time),
	}
}

// Allow reports whether key may proceed now.
func (r *Registry) Allow(key string) bool {
	r.mu.Lock()
	defer r.mu.Unlock()
	now := time.Now()
	if t, ok := r.last[key]; ok && now.Sub(t) < r.interval {
		return false
	}
	r.last[key] = now
	return true
}

// Remove forgets any stored state for key, so its next Allow call
// is treated as a fresh, unthrottled key.
func (r *Registry) Remove(key string) {
	r.mu.Lock()
	delete(r.last, key)
	r.mu.Unlock()
}
