// ROT13 applies the ROT13 substitution cipher to s, rotating ASCII letters by
// 13 positions. Non-letter runes are returned unchanged. Applying it twice
// restores the original string.
func ROT13(s string) string {
	shift := func(r rune) rune {
		switch {
		case r >= 'a' && r <= 'z':
			return 'a' + (r-'a'+13)%26
		case r >= 'A' && r <= 'Z':
			return 'A' + (r-'A'+13)%26
		default:
			return r
		}
	}
	return string(mapRunes(s, shift))
}

func mapRunes(s string, f func(rune) rune) []rune {
	out := make([]rune, 0, len(s))
	for _, r := range s {
		out = append(out, f(r))
	}
	return out
}
