// Pair holds one element from each of two slices joined by Zip.
type Pair[A, B any] struct {
	First  A
	Second B
}

// Zip combines two slices element-wise into a slice of Pairs. The result
// length is the shorter of the two inputs.
func Zip[A, B any](as []A, bs []B) []Pair[A, B] {
	n := len(as)
	if len(bs) < n {
		n = len(bs)
	}
	pairs := make([]Pair[A, B], n)
	for i := 0; i < n; i++ {
		pairs[i] = Pair[A, B]{First: as[i], Second: bs[i]}
	}
	return pairs
}
