// LCM returns the least common multiple of a and b. It returns 0 if
// either argument is 0. The result is always non-negative.
func LCM(a, b int) int {
	if a == 0 || b == 0 {
		return 0
	}
	g := GCD(a, b)
	r := (a / g) * b
	if r < 0 {
		r = -r
	}
	return r
}
