// IntPow returns base raised to the power exp using exponentiation by
// squaring. A negative exponent returns 0, matching integer semantics.
func IntPow(base, exp int) int {
	if exp < 0 {
		return 0
	}
	result := 1
	for exp > 0 {
		if exp&1 == 1 {
			result *= base
		}
		base *= base
		exp >>= 1
	}
	return result
}
