// HumanizeDuration renders d as a compact, human-readable string such as
// "2h 5m 3s". Sub-second durations are reported in milliseconds, and a zero
// duration returns "0s". Negative durations are prefixed with "-".
func HumanizeDuration(d time.Duration) string {
	if d == 0 {
		return "0s"
	}

	neg := d < 0
	if neg {
		d = -d
	}

	var parts []string
	if h := d / time.Hour; h > 0 {
		parts = append(parts, fmt.Sprintf("%dh", h))
		d -= h * time.Hour
	}
	if m := d / time.Minute; m > 0 {
		parts = append(parts, fmt.Sprintf("%dm", m))
		d -= m * time.Minute
	}
	if s := d / time.Second; s > 0 {
		parts = append(parts, fmt.Sprintf("%ds", s))
		d -= s * time.Second
	}
	if len(parts) == 0 {
		parts = append(parts, fmt.Sprintf("%dms", d/time.Millisecond))
	}

	out := strings.Join(parts, " ")
	if neg {
		return "-" + out
	}
	return out
}
