// AgeInYears returns the number of full years between birth and asOf. The
// result is zero when asOf is before birth. The calendar date is used, so a
// birthday that has not yet occurred in the asOf year is not counted.
func AgeInYears(birth, asOf time.Time) int {
	if asOf.Before(birth) {
		return 0
	}

	years := asOf.Year() - birth.Year()

	// Subtract one if the birthday has not happened yet this year.
	if asOf.Month() < birth.Month() ||
		(asOf.Month() == birth.Month() && asOf.Day() < birth.Day()) {
