// BusinessDaysBetween counts the weekdays (Monday through Friday) in the
// half-open interval [start, end). Saturdays and Sundays are excluded. If end
// is not after start, the result is zero.
func BusinessDaysBetween(start, end time.Time) int {
	if !end.After(start) {
		return 0
	}

	// Normalize to midnight so partial days do not skew the count.
	day := time.Date(start.Year(), start.Month(), start.Day(), 0, 0, 0, 0, start.Location())
	last := time.Date(end.Year(), end.Month(), end.Day(), 0, 0, 0, 0, end.Location())

	count := 0
	for day.Before(last) {
		switch day.Weekday() {
		case time.Saturday, time.Sunday:
		default:
			count++
		}
		day = day.AddDate(0, 0, 1)
	}
	return count
}
