// BubbleSort sorts xs in ascending order in place using the bubble sort
// algorithm. It is stable and operates directly on the provided slice.
func BubbleSort(xs []int) {
	for i := 0; i < len(xs); i++ {
		swapped := false
		for j := 0; j < len(xs)-i-1; j++ {
			if xs[j] > xs[j+1] {
				xs[j], xs[j+1] = xs[j+1], xs[j]
				swapped = true
			}
		}
		if !swapped {
