import "cmp"

// QuickSort returns a new sorted slice containing the elements of xs in
// ascending order. It uses the Lomuto partition scheme and works for any
// ordered element type.
func QuickSort[T cmp.Ordered](xs []T) []T {
	out := make([]T, len(xs))
	copy(out, xs)
	quick(out, 0, len(out)-1)
	return out
}

func quick[T cmp.Ordered](xs []T, lo, hi int) {
	if lo >= hi {
		return
	}
	pivot := xs[hi]
	i := lo
	for j := lo; j < hi; j++ {
		if xs[j] < pivot {
			xs[i], xs[j] = xs[j], xs[i]
			i++
		}
	}
	xs[i], xs[hi] = xs[hi], xs[i]
	quick(xs, lo, i-1)
	quick(xs, i+1, hi)
}
