// MergeSort returns a new slice with the elements of xs sorted in ascending
// order using the classic top-down merge sort algorithm. It is stable.
func MergeSort(xs []int) []int {
	if len(xs) <= 1 {
		out := make([]int, len(xs))
		copy(out, xs)
		return out
	}
	mid := len(xs) / 2
	left := MergeSort(xs[:mid])
	right := MergeSort(xs[mid:])
	return mergeInts(left, right)
}

func mergeInts(a, b []int) []int {
	out := make([]int, 0, len(a)+len(b))
	i, j := 0, 0
	for i < len(a) && j < len(b) {
		if a[i] <= b[j] {
			out = append(out, a[i])
			i++
		} else {
			out = append(out, b[j])
			j++
		}
	}
	out = append(out, a[i:]...)
	out = append(out, b[j:]...)
	return out
}
