func (h *intHeap) Pop() any {
	old := *h
	n := len(old)
	v := old[n-1]
	*h = old[:n-1]
	return v
}

// HeapSort returns a new slice with the elements of xs sorted in ascending
// order using a binary heap from container/heap.
func HeapSort(xs []int) []int {
	h := make(intHeap, len(xs))
	copy(h, xs)
	heap.Init(&h)
	out := make([]int, 0, len(xs))
	for h.Len() > 0 {
		out = append(out, heap.Pop(&h).(int))
	}
	return out
}

