import "sync"

// WorkerPool runs fn over each input using n concurrent workers and returns
// the results. The order of results is not guaranteed.
func WorkerPool[T, R any](n int, inputs []T, fn func(T) R) []R {
	if n < 1 {
		n = 1
	}
	jobs := make(chan T)
	results := make(chan R)

	var wg sync.WaitGroup
	for i := 0; i < n; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for job := range jobs {
				results <- fn(job)
			}
		}()
	}

	go func() {
		for _, in := range inputs {
			jobs <- in
		}
		close(jobs)
	}()

	go func() {
		wg.Wait()
		close(results)
	}()

	out := make([]R, 0, len(inputs))
	for r := range results {
		out = append(out, r)
	}
	return out
}
