package sandbox

import "cmp"

// MaxHeap is a generic binary max-heap backed by a slice.
type MaxHeap[T cmp.Ordered] struct {
	data []T
}

// Len reports the number of elements in the heap.
func (h *MaxHeap[T]) Len() int { return len(h.data) }

// Push adds v to the heap, restoring the heap property by sifting up.
func (h *MaxHeap[T]) Push(v T) {
	h.data = append(h.data, v)
	i := len(h.data) - 1
	for i > 0 {
		parent := (i - 1) / 2
		if h.data[parent] >= h.data[i] {
			break
		}
		h.data[parent], h.data[i] = h.data[i], h.data[parent]
		i = parent
	}
}

// Pop removes and returns the maximum element, reporting whether one existed.
func (h *MaxHeap[T]) Pop() (T, bool) {
	var zero T
	n := len(h.data)
	if n == 0 {
		return zero, false
	}
	top := h.data[0]
	h.data[0] = h.data[n-1]
	h.data = h.data[:n-1]
	n--
	i := 0
	for {
		l, r, largest := 2*i+1, 2*i+2, i
		if l < n && h.data[l] > h.data[largest] {
			largest = l
		}
		if r < n && h.data[r] > h.data[largest] {
			largest = r
		}
		if largest == i {
			break
		}
		h.data[i], h.data[largest] = h.data[largest], h.data[i]
		i = largest
	}
	return top, true
}
