package sandbox

// RingBuffer is a fixed-capacity circular FIFO buffer of ints.
type RingBuffer struct {
	buf  []int
	head int
	size int
}

// NewRingBuffer returns a ring buffer that holds up to capacity items.
func NewRingBuffer(capacity int) *RingBuffer {
	if capacity < 1 {
		capacity = 1
	}
	return &RingBuffer{buf: make([]int, capacity)}
}

// Push appends v, overwriting the oldest value when the buffer is full.
func (b *RingBuffer) Push(v int) {
	tail := (b.head + b.size) % len(b.buf)
	if b.size == len(b.buf) {
		b.head = (b.head + 1) % len(b.buf)
	} else {
		b.size++
	}
	b.buf[tail] = v
}

// Pop removes and returns the oldest value, reporting whether one existed.
func (b *RingBuffer) Pop() (int, bool) {
	if b.size == 0 {
		return 0, false
	}
	v := b.buf[b.head]
	b.head = (b.head + 1) % len(b.buf)
	b.size--
	return v, true
}

// Len reports how many items the buffer currently holds.
func (b *RingBuffer) Len() int { return b.size }
