// FromSlice builds a singly linked list from vals and returns its head.
func FromSlice[T any](vals []T) *Node[T] {
	var head *Node[T]
	for i := len(vals) - 1; i >= 0; i-- {
		head = &Node[T]{Val: vals[i], Next: head}
	}
	return head
