func Reverse[T any](head *Node[T]) *Node[T] {
	var prev *Node[T]
	for head != nil {
		next := head.Next
		head.Next = prev
		prev = head
		head = next
	}
	return prev
}

// ToSlice collects the list values into a slice.
func ToSlice[T any](head *Node[T]) []T {
	var out []T
	for n := head; n != nil; n = n.Next {
		out = append(out, n.Val)
	}
	return out
