// Josephus solves the Josephus problem for n people standing in a circle,
// eliminating every k-th person, and returns the 1-based positions in the
// order they are eliminated (the final survivor is last).
func Josephus(n, k int) []int {
	if n <= 0 || k <= 0 {
		return nil
	}
	r := ring.New(n)
	for i := 1; i <= n; i++ {
		r.Value = i
		r = r.Next()
	}
	r = r.Prev() // position just before person 1
	order := make([]int, 0, n)
	for r.Len() > 1 {
		for i := 0; i < k-1; i++ {
			r = r.Next()
		}
		victim := r.Unlink(1) // removes the node following r
		order = append(order, victim.Value.(int))
	}
	order = append(order, r.Value.(int))
	return order
}
