// ParseIPv4 parses a dotted-decimal IPv4 address such as "192.168.1.1"
// into its four octets. It returns an error if the address is malformed
// or any octet is out of the 0-255 range.
func ParseIPv4(s string) ([4]byte, error) {
	var out [4]byte
	parts := strings.Split(s, ".")
	if len(parts) != 4 {
		return out, fmt.Errorf("invalid IPv4 %q: expected 4 octets, got %d", s, len(parts))
	}
	for i, p := range parts {
		if p == "" || (len(p) > 1 && p[0] == '0') {
			return out, fmt.Errorf("invalid octet %q", p)
		}
		n, err := strconv.Atoi(p)
		if err != nil {
			return out, fmt.Errorf("invalid octet %q: %w", p, err)
		}
		if n < 0 || n > 255 {
			return out, fmt.Errorf("octet %d out of range", n)
		}
		out[i] = byte(n)
	}
	return out, nil
