// RGB holds the red, green and blue components of a color.
type RGB struct {
	R, G, B uint8
}

// ParseHexColor parses a CSS-style hex color such as "#aabbcc" or "#abc"
// (shorthand) into an RGB value. The leading '#' is required.
func ParseHexColor(s string) (RGB, error) {
	var c RGB
	if !strings.HasPrefix(s, "#") {
		return c, fmt.Errorf("missing leading '#' in %q", s)
	}
	h := s[1:]
	switch len(h) {
	case 3:
		h = string([]byte{h[0], h[0], h[1], h[1], h[2], h[2]})
	case 6:
	default:
		return c, fmt.Errorf("invalid hex length in %q", s)
	}
	v := make([]uint8, 3)
	for i := 0; i < 3; i++ {
		hi, err := hexVal(h[i*2])
		if err != nil {
			return c, err
		}
		lo, err := hexVal(h[i*2+1])
		if err != nil {
			return c, err
		}
		v[i] = hi<<4 | lo
	}
	return RGB{R: v[0], G: v[1], B: v[2]}, nil
}

func hexVal(b byte) (uint8, error) {
	switch {
	case b >= '0' && b <= '9':
		return b - '0', nil
	case b >= 'a' && b <= 'f':
		return b - 'a' + 10, nil
	case b >= 'A' && b <= 'F':
		return b - 'A' + 10, nil
	}
	return 0, fmt.Errorf("invalid hex digit %q", string(b))
}
