// address and returns its normalized (lowercased domain) form. It rejects
// addresses that include a display name such as "Bob <bob@x.com>".
func ValidateEmail(s string) (string, error) {
	addr, err := mail.ParseAddress(s)
	if err != nil {
		return "", fmt.Errorf("invalid email %q: %w", s, err)
	}
	if addr.Name != "" || addr.Address != strings.TrimSpace(s) {
		return "", fmt.Errorf("address must be bare, got %q", s)
	}
	at := strings.LastIndex(addr.Address, "@")
	local, domain := addr.Address[:at], strings.ToLower(addr.Address[at+1:])
	if !strings.Contains(domain, ".") {
		return "", fmt.Errorf("domain %q has no dot", domain)
	}
	return local + "@" + domain, nil
