// ValidateLuhn checks whether a numeric string (such as a credit-card
// number) passes the Luhn checksum. Spaces and hyphens are ignored. It
// returns an error if the input contains non-digit characters or is empty.
func ValidateLuhn(s string) error {
	clean := strings.NewReplacer(" ", "", "-", "").Replace(s)
	if clean == "" {
		return fmt.Errorf("empty number")
	}
	var sum int
	double := false
	for i := len(clean) - 1; i >= 0; i-- {
		c := clean[i]
		if c < '0' || c > '9' {
			return fmt.Errorf("invalid digit %q", string(c))
		}
		d := int(c - '0')
		if double {
			d *= 2
			if d > 9 {
				d -= 9
			}
		}
		sum += d
		double = !double
	}
	if sum%10 != 0 {
		return fmt.Errorf("checksum failed for %q", s)
	}
	return nil
}
