// ParseConfig parses simple INI-style "key = value" lines into a map.
// Blank lines and lines beginning with '#' or ';' are treated as comments.
// Duplicate keys and lines lacking '=' produce an error.
func ParseConfig(text string) (map[string]string, error) {
	out := make(map[string]string)
	sc := bufio.NewScanner(strings.NewReader(text))
	line := 0
	for sc.Scan() {
		line++
		raw := strings.TrimSpace(sc.Text())
		if raw == "" || raw[0] == '#' || raw[0] == ';' {
			continue
		}
		k, v, ok := strings.Cut(raw, "=")
		if !ok {
			return nil, fmt.Errorf("line %d: missing '=' in %q", line, raw)
		}
		key := strings.TrimSpace(k)
		if key == "" {
			return nil, fmt.Errorf("line %d: empty key", line)
		}
		if _, dup := out[key]; dup {
			return nil, fmt.Errorf("line %d: duplicate key %q", line, key)
		}
		out[key] = strings.TrimSpace(v)
	}
	if err := sc.Err(); err != nil {
		return nil, err
	}
	return out, nil
}
