	s = strings.TrimPrefix(s, "v")
	core, pre, _ := strings.Cut(s, "-")
	parts := strings.Split(core, ".")
	if len(parts) != 3 {
		return sv, fmt.Errorf("expected major.minor.patch, got %q", core)
	}
	dst := []*int{&sv.Major, &sv.Minor, &sv.Patch}
	for i, p := range parts {
		n, err := strconv.Atoi(p)
		if err != nil || n < 0 {
			return sv, fmt.Errorf("invalid version component %q", p)
		}
		*dst[i] = n
	}
	sv.PreRelease = pre
	return sv, nil
}

// String renders the SemVer back to its canonical string form.
func (s SemVer) String() string {
	out := fmt.Sprintf("%d.%d.%d", s.Major, s.Minor, s.Patch)
	if s.PreRelease != "" {
		out += "-" + s.PreRelease
	}
	return out
}
