package sandbox

import (
	"fmt"
	"unicode"
)

// ValidatePassword enforces a password policy: at least minLen runes and
// at least one uppercase letter, one lowercase letter, one digit and one
// punctuation/symbol. It returns a descriptive error on the first failure.
func ValidatePassword(pw string, minLen int) error {
	if len([]rune(pw)) < minLen {
		return fmt.Errorf("password must be at least %d characters", minLen)
	}
	var upper, lower, digit, special bool
	for _, r := range pw {
		switch {
		case unicode.IsUpper(r):
			upper = true
		case unicode.IsLower(r):
			lower = true
		case unicode.IsDigit(r):
			digit = true
		case unicode.IsPunct(r) || unicode.IsSymbol(r):
			special = true
		}
	}
	switch {
	case !upper:
		return fmt.Errorf("password needs an uppercase letter")
	case !lower:
		return fmt.Errorf("password needs a lowercase letter")
	case !digit:
		return fmt.Errorf("password needs a digit")
	case !special:
		return fmt.Errorf("password needs a special character")
	}
	return nil
}
