package sandbox

import (
	"encoding/csv"
	"fmt"
	"strings"
)

// ParseCSVRecord parses a single CSV line into its fields, honoring
// double-quoted fields that may contain commas. It requires exactly the
// given number of columns, which is handy for validating fixed-shape rows.
func ParseCSVRecord(line string, wantCols int) ([]string, error) {
	r := csv.NewReader(strings.NewReader(line))
	r.FieldsPerRecord = wantCols
	rec, err := r.Read()
	if err != nil {
		return nil, fmt.Errorf("parse CSV %q: %w", line, err)
	}
	for i, f := range rec {
		rec[i] = strings.TrimSpace(f)
		if rec[i] == "" {
			return nil, fmt.Errorf("column %d is empty", i)
		}
	}
	return rec, nil
}
